#include <iostream>

class Base
{
public:
    virtual ~Base()
    {
        std::cout << "Destroying Base" << '\n';
    }
};

class Derived : public Base
{
public:
    ~Derived() override
    {
        std::cout << "Destroying Derived" << '\n';
    }
};

int main()
{
    int n{};
    std::cin >> n;

    for (int i{0}; i < n; ++i)
    {
        Base* ptr{new Derived{}};
        delete ptr;
    }

    std::cout << "Done" << '\n';

    return 0;
}

