#include <iostream>
#include <string>

class Base
{
public:
    Base()
    {
        std::cout << "Base created" << '\n';
    }

    virtual ~Base()
    {
        std::cout << "Base destroyed" << '\n';
    }
};

class Resource : public Base
{
    std::string m_label{};
    int m_size{};

public:
    Resource(const std::string& label, int size)
        : m_label{label}
        , m_size{size}
    {
        std::cout << "Resource acquired: " << m_label << " size " << m_size << '\n';
    }

    ~Resource() override
    {
        std::cout << "Resource released: " << m_label << " size " << m_size << '\n';
    }

    void use() const
    {
        std::cout << "Using: " << m_label << " size " << m_size << '\n';
    }
};

int main()
{
    std::string label{};
    int size{};
    std::cin >> label >> size;

    Base* ptr{new Resource{label, size}};
    static_cast<Resource*>(ptr)->use();
    delete ptr;

    return 0;
}
